class Solution {
public:
    long long solve(std::vector<std::vector<long long>> grid) {
        int m = grid.size();
        int n = grid[0].size();

        // The constraint m * n <= 1000 is key here.
        // The path length is fixed: (m-1) + (n-1) + 1 = m + n - 1.
        // Since m*n <= 1000, m+n is relatively small (max around 2*32 or 1000 if m=1 or n=1).
        // A standard DP approach would be O(m*n * 2^B) if we tracked XOR states, which is too large (2^10).

        // Since the path length is small, we can use BFS/DFS or Meet-in-the-Middle.
        // With m*n <= 1000, the path length is at most 1000.
        // The number of paths is C(m+n-2, m-1), which can be very large.

        // Let's use Meet-in-the-Middle (MITM).
        // The total number of steps is K = m + n - 2 (number of moves).
        // We aim to meet at a diagonal where the number of steps taken from (0,0) equals the steps remaining to (m-1, n-1).
        // A good meeting point is when the sum of coordinates i + j = target_sum.
        // The total number of steps to reach any cell (i, j) is i + j.
        // We should aim for a sum around (m + n - 2) / 2.

        int target_sum = (m + n - 2) / 2;

        // Part 1: BFS/DFS from (0, 0) up to target_sum
        // Stores: map<sum_of_coords, set<xor_values>>
        // Since we stop at a fixed coordinate sum, we don't need to store 'sum_of_coords' explicitly in the map key.
        // We use a map keyed by the set of XOR values achievable at a given coordinate sum.
        // For simplicity and robustness in MITM, we map (i, j) to the set of XOR values.

        // dist1[i][j] stores the set of all possible XOR sums to reach (i, j)
        // However, we only care about cells where i + j == target_sum or i+j == target_sum + 1.

        // We will use a map from (i+j) to a set of pairs {i, j} -> {xor_values}.
        // Or, since we are traversing level by level (by i+j), we can use a map keyed by i+j.

        // State: map<int, map<pair<int, int>, set<int>>> 
        // This is too complex. Let's stick to level-by-level processing (BFS style).

        // level_data[k] = set of {xor_value} achievable at any cell (i, j) such that i+j = k.
        // Since we need to match coordinates, we must store the coordinates along with the XOR sum.

        // level_map[k] = map<(i, j), set<xor_values>> where i+j = k.
        // Given m*n <= 1000, the number of cells is small enough that we can afford to store the sets of XOR values for each cell.

        // Let's refine the structure for the first half.
        // map1: Stores the set of achievable XOR sums for each cell (i, j) reached in the first half.
        // Since we stop at a specific sum, we iterate up to target_sum.

        // map1[i][j] = set of XOR sums to reach (i, j)
        vector<vector<set<int>>> map1(m, vector<set<int>>(n));

        map1[0][0].insert(grid[0][0]);

        for (int k = 1; k <= target_sum; ++k) {
            for (int i = 0; i < m; ++i) {
                for (int j = 0; j < n; ++j) {
                    if (i + j != k) continue;

                    // From top (i-1, j)
                    if (i > 0) {
                        for (int xor_val : map1[i - 1][j]) {
                            map1[i][j].insert(xor_val ^ grid[i][j]);
                        }
                    }
                    // From left (i, j-1)
                    if (j > 0) {
                        for (int xor_val : map1[i][j - 1]) {
                            map1[i][j].insert(xor_val ^ grid[i][j]);
                        }
                    }
                }
            }
        }

        // Part 2: BFS/DFS from (m-1, n-1) backwards up to target_sum
        // We start from (m-1, n-1) and move UP or LEFT.
        // The total path length is m+n-1. The midpoint is roughly at steps = target_sum.
        // The number of steps from (m-1, n-1) backwards to reach a cell (i, j) is (m-1-i) + (n-1-j).
        // We want this step count to be close to (m+n-2) - target_sum.

        // Let's simplify: we stop when i+j reaches target_sum or target_sum+1.
        // The number of steps taken from (m-1, n-1) backwards is (m-1-i) + (n-1-j).
        // If i+j = target_sum, then (m-1-i) + (n-1-j) = m+n-2 - (i+j) = m+n-2 - target_sum.

        // map2[i][j] = set of XOR sums to reach (m-1, n-1) from (i, j)
        vector<vector<set<int>>> map2(m, vector<set<int>>(n));

        map2[m - 1][n - 1].insert(grid[m - 1][n - 1]);

        for (int k = m + n - 2; k > target_sum; --k) {
            for (int i = 0; i < m; ++i) {
                for (int j = 0; j < n; ++j) {
                    if (i + j != k) continue;

                    // From bottom (i+1, j) in reverse path (i.e., coming from i+1, j)
                    if (i < m - 1) {
                        for (int xor_val : map2[i + 1][j]) {
                            map2[i][j].insert(xor_val ^ grid[i][j]);
                        }
                    }
                    // From right (i, j+1) in reverse path (i.e., coming from i, j+1)
                    if (j < n - 1) {
                        for (int xor_val : map2[i][j + 1]) {
                            map2[i][j].insert(xor_val ^ grid[i][j]);
                        }
                    }
                }
            }
        }


