        int min_xor = (1 << 11) - 1; // Max possible XOR value is < 1024

        // We combine results for cells (i, j) where i + j is close to target_sum.
        // The meeting point is any cell (i, j) such that i + j = target_sum or i + j = target_sum + 1.

        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                if (i + j < target_sum || i + j > target_sum + 1) continue;

                if (map1[i][j].empty() || map2[i][j].empty()) continue;

                // Crucial correction for overlap:
                // When combining, the value grid[i][j] is counted in both map1 and map2.
                // Let XOR1 be the path XOR up to (i-1, j) or (i, j-1).
                // Map1 stores XOR1 ^ grid[i][j].
                // Let XOR2 be the path XOR from (i+1, j) or (i, j+1) to end.
                // Map2 stores grid[i][j] ^ XOR2.

                // Total XOR = XOR1 ^ grid[i][j] ^ XOR2
                // If we use map1[i][j] and map2[i][j]:
                // Value in map1[i][j] = P1_prefix ^ grid[i][j]
                // Value in map2[i][j] = grid[i][j] ^ P2_suffix
                // P1_prefix is XOR up to the predecessor of (i, j).
                // P2_suffix is XOR from the successor of (i, j) to the end.
                // The total path XOR is P1_prefix ^ grid[i][j] ^ P2_suffix.
                // Total XOR = (map1[i][j] ^ grid[i][j]) ^ (map2[i][j] ^ grid[i][j])
                // Total XOR = map1[i][j] ^ map2[i][j]  (since X ^ Y ^ Y = X)

                for (int xor1 : map1[i][j]) {
                    for (int xor2 : map2[i][j]) {
                        // xor1 includes grid[i][j]
                        // xor2 includes grid[i][j]
                        // The combined path XOR is xor1 ^ xor2 ^ grid[i][j]
                        int total_xor = xor1 ^ xor2 ^ grid[i][j];
                        min_xor = min(min_xor, total_xor);
                    }
                }
            }
        }

        // Edge case: if m=1 or n=1, the MITM structure might miss the trivial path if target_sum logic is too strict.
        // However, if m=1, target_sum = (n-1)/2. The loop runs correctly for the single row.
        // If m=1, the only meeting point is (0, j) where j=target_sum or j=target_sum+1.

        if (m == 1 && n == 1) {
            return grid[0][0];
        }

        return min_xor;
    }
};
